!function(){const e=document.querySelectorAll(".reveal");if(!("IntersectionObserver"in window))return void e.forEach(e=>e.classList.add("visible"));const r=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("visible"),r.unobserve(e.target))})},{threshold:.1});e.forEach(e=>r.observe(e))}();